    99→class G1ConcPhaseTimer : public GCTraceConcTimeImpl<LogLevel::Info, LOG_TAGS(gc, marking)> {
   100→  G1ConcurrentMark* _cm;
   101→
   102→ public:
   103→  G1ConcPhaseTimer(G1ConcurrentMark* cm, const char* title) :
   104→    GCTraceConcTimeImpl<LogLevel::Info,  LogTag::_gc, LogTag::_marking>(title),
   105→    _cm(cm)
   106→  {
   107→    _cm->gc_timer_cm()->register_gc_concurrent_start(title);
   108→  }
   109→
   110→  ~G1ConcPhaseTimer() {
   111→    _cm->gc_timer_cm()->register_gc_concurrent_end();
   112→  }
   113→};
   114→
   115→void G1ConcurrentMarkThread::run_service() {
   116→  _vtime_start = os::elapsedVTime();
   117→
   118→  while (wait_for_next_cycle()) {
   119→    assert(in_progress(), "must be");
   120→
   121→    GCIdMark gc_id_mark;
   122→    FormatBuffer<128> title("Concurrent %s Cycle", _state == FullMark ? "Mark" : "Undo");
   123→    GCTraceConcTime(Info, gc) tt(title);
   124→
   125→    concurrent_cycle_start();
   126→
   127→    if (_state == FullMark) {
   128→      concurrent_mark_cycle_do();
   129→    } else {
   130→      assert(_state == UndoMark, "Must do undo mark but is %d", _state);
   131→      concurrent_undo_cycle_do();
   132→    }
   133→
   134→    concurrent_cycle_end(_state == FullMark && !_cm->has_aborted());
   135→
   136→    _vtime_accum = (os::elapsedVTime() - _vtime_start);
   137→
   138→    update_threads_cpu_time();
   139→  }
   140→  _cm->root_regions()->cancel_scan();
   141→}
   142→
   143→void G1ConcurrentMarkThread::stop_service() {
   144→  if (in_progress()) {
   145→    // We are not allowed to abort the marking threads during root region scan.
   146→    // Needs to be done separately.
   147→    _cm->root_region_scan_abort_and_wait();
   148→
   149→    _cm->abort_marking_threads();
   150→  }

