   314→void G1ConcurrentMarkThread::concurrent_undo_cycle_do() {
   315→  HandleMark hm(Thread::current());
   316→  ResourceMark rm;
   317→
   318→  // We can (and should) abort if there has been a concurrent cycle abort for
   319→  // some reason.
   320→  if (_cm->has_aborted()) { return; }
   321→
   322→  _cm->flush_all_task_caches();
   323→
   324→  // Phase 1: Clear CLD claimed marks.
   325→  if (phase_clear_cld_claimed_marks()) return;
